-- AREAS
-- ============================================
insert into public.areas (slug, name, description, region) values
  ('costa-adeje', '{"es":"Costa Adeje","en":"Costa Adeje","de":"Costa Adeje","fr":"Costa Adeje","ru":"Коста Адехе","it":"Costa Adeje"}', '{"es":"La zona turística más exclusiva del sur de Tenerife, con playas de arena dorada, resorts de lujo y una animada vida nocturna.","en":"The most exclusive tourist area in southern Tenerife, with golden sand beaches, luxury resorts and vibrant nightlife.","de":"Das exklusivste Touristengebiet im Süden Teneriffas mit goldenen Sandstränden, Luxusresorts und pulsierendem Nachtleben."}', 'south'),
  ('los-cristianos', '{"es":"Los Cristianos","en":"Los Cristianos","de":"Los Cristianos","fr":"Los Cristianos","ru":"Лос Кристианос","it":"Los Cristianos"}', '{"es":"Antiguo pueblo pesquero convertido en un animado centro turístico con playas familiares y un encantador paseo marítimo.","en":"Former fishing village turned lively tourist hub with family-friendly beaches and a charming promenade.","de":"Ehemaliges Fischerdorf, heute ein lebhaftes Touristenzentrum mit familienfreundlichen Stränden."}', 'south'),
  ('puerto-de-la-cruz', '{"es":"Puerto de la Cruz","en":"Puerto de la Cruz","de":"Puerto de la Cruz","fr":"Puerto de la Cruz","ru":"Пуэрто де ла Крус","it":"Puerto de la Cruz"}', '{"es":"La joya del norte de Tenerife, con su casco histórico, jardines botánicos y el icónico Lago Martiánez.","en":"The jewel of northern Tenerife, with its historic old town, botanical gardens and iconic Lago Martiánez.","de":"Das Juwel des Nordens von Teneriffa mit historischer Altstadt, botanischen Gärten und dem ikonischen Lago Martiánez."}', 'north'),
  ('santa-cruz', '{"es":"Santa Cruz de Tenerife","en":"Santa Cruz de Tenerife","de":"Santa Cruz de Teneriffa","fr":"Santa Cruz de Tenerife","ru":"Санта Крус де Тенерифе","it":"Santa Cruz de Tenerife"}', '{"es":"La capital de la isla, centro cultural y comercial con arquitectura impresionante y el famoso Carnaval.","en":"The island capital, cultural and commercial center with impressive architecture and the famous Carnival.","de":"Die Inselhauptstadt, kulturelles und kommerzielles Zentrum mit beeindruckender Architektur und dem berühmten Karneval."}', 'central'),
  ('la-laguna', '{"es":"San Cristóbal de La Laguna","en":"San Cristóbal de La Laguna","de":"San Cristóbal de La Laguna","fr":"San Cristóbal de La Laguna","ru":"Ла Лагуна","it":"San Cristóbal de La Laguna"}', '{"es":"Ciudad Patrimonio de la Humanidad por la UNESCO, universidad histórica y el centro cultural de Tenerife.","en":"UNESCO World Heritage city, historic university town and the cultural heart of Tenerife.","de":"UNESCO-Weltkulturerbe, historische Universitätsstadt und kulturelles Herz Teneriffas."}', 'north'),
  ('los-gigantes', '{"es":"Los Gigantes","en":"Los Gigantes","de":"Los Gigantes","fr":"Los Gigantes","ru":"Лос Гигантес","it":"Los Gigantes"}', '{"es":"Espectaculares acantilados de hasta 600m sobre el mar, avistamiento de ballenas y puestas de sol inolvidables.","en":"Spectacular cliffs rising 600m above the sea, whale watching and unforgettable sunsets.","de":"Spektakuläre Klippen bis zu 600m über dem Meer, Walbeobachtung und unvergessliche Sonnenuntergänge."}', 'west'),
  ('teide', '{"es":"Parque Nacional del Teide","en":"Teide National Park","de":"Teide-Nationalpark","fr":"Parc National du Teide","ru":"Национальный парк Тейде","it":"Parco Nazionale del Teide"}', '{"es":"El volcán más alto de España y Patrimonio de la Humanidad, con paisajes lunares y las mejores estrellas de Europa.","en":"Spain''s highest volcano and UNESCO World Heritage site, with lunar landscapes and Europe''s best stargazing.","de":"Spaniens höchster Vulkan und UNESCO-Welterbe mit Mondlandschaften und Europas bestem Sternenhimmel."}', 'central'),
  ('anaga', '{"es":"Macizo de Anaga","en":"Anaga Mountains","de":"Anaga-Gebirge","fr":"Massif d''Anaga","ru":"Горы Анага","it":"Monti di Anaga"}', '{"es":"Reserva de la Biosfera con bosques de laurisilva, senderos espectaculares y playas remotas.","en":"Biosphere Reserve with ancient laurel forests, spectacular hiking trails and remote beaches.","de":"Biosphärenreservat mit uralten Lorbeerwäldern, spektakulären Wanderwegen und abgelegenen Stränden."}', 'north');

