  ('nightlife', 'Music', '{"es":"Vida Nocturna","en":"Nightlife","de":"Nachtleben","fr":"Vie Nocturne","ru":"Ночная Жизнь","it":"Vita Notturna"}', '{"es":"Bares, discotecas, música en vivo y espectáculos","en":"Bars, clubs, live music and shows","de":"Bars, Clubs, Livemusik und Shows","fr":"Bars, clubs, musique live et spectacles","ru":"Бары, клубы, живая музыка и шоу","it":"Bar, club, musica dal vivo e spettacoli"}', 6),
  ('shopping', 'ShoppingBag', '{"es":"Compras","en":"Shopping","de":"Einkaufen","fr":"Shopping","ru":"Шопинг","it":"Shopping"}', '{"es":"Centros comerciales, mercados locales y productos artesanales","en":"Shopping centers, local markets and artisan products","de":"Einkaufszentren, lokale Märkte und handwerkliche Produkte","fr":"Centres commerciaux, marchés locaux et produits artisanaux","ru":"Торговые центры, местные рынки и ремесленные изделия","it":"Centri commerciali, mercati locali e prodotti artigianali"}', 7),
  ('family', 'Baby', '{"es":"Familia","en":"Family Fun","de":"Familienspaß","fr":"Famille","ru":"Для Семьи","it":"Famiglia"}', '{"es":"Parques temáticos, parques acuáticos, zoológicos y actividades para niños","en":"Theme parks, water parks, zoos and activities for children","de":"Themenparks, Wasserparks, Zoos und Aktivitäten für Kinder","fr":"Parcs à thème, parcs aquatiques, zoos et activités pour enfants","ru":"Тематические парки, аквапарки, зоопарки и развлечения для детей","it":"Parchi tematici, parchi acquatici, zoo e attività per bambini"}', 8),
  ('wellness', 'Sparkles', '{"es":"Bienestar y Spa","en":"Wellness & Spa","de":"Wellness & Spa","fr":"Bien-être & Spa","ru":"Велнес и Спа","it":"Benessere e Spa"}', '{"es":"Spas, retiros de yoga, terapias holísticas y relax","en":"Spas, yoga retreats, holistic therapies and relaxation","de":"Spas, Yoga-Retreats, ganzheitliche Therapien und Entspannung","fr":"Spas, retraites de yoga, thérapies holistiques et relaxation","ru":"Спа, йога-ретриты, холистические терапии и релаксация","it":"Spa, ritiri yoga, terapie olistiche e relax"}', 9);

